rConfirmationNumber":"আমরা আপনার আবেদনপত্রটি পেয়েছি","gotYourConfirmationNumberOnYourBehalf":"আমরা আপনার পক্ষ থেকে একটি আবেদনপত্র পেয়েছি"},"leasingAgent":{"officeHours":"অফিসের সময়সূচী:","propertyManager":"সম্পত্তি ব্যবস্থাপক","contactAgentToUpdateInfo":"আপনার আবেদনে তথ্য হালনাগাদ করার প্রয়োজন হলে, পুনরায় আবেদন করবেন না। পরিবর্তে, এই তালিকার এজেন্টের সাথে যোগাযোগ করুন।","contactAgentForQuestions":"এই আবেদনপত্রটি সম্পর্কে আপনার কোনো প্রশ্ন থাকলে, অনুগ্রহ করে এই তালিকার এজেন্টের সাথে যোগাযোগ করুন।"},"mfaCodeEmail":{"message":"আপনার অ্যাকাউন্টের জন্য অ্যাক্সেস কোড অনুরোধ করা হয়েছে।","mfaCode":"আপনার অ্যাক্সেস কোড হলো: %{singleUseCode}"},"forgotPassword":{"subject":"আপনার পাসওয়ার্ড ভুলে গেছেন?","callToAction":"আপনি যদি এই অনুরোধটি করে থাকেন, তবে আপনার পাসওয়ার্ড পুনরায় সেট করতে অনুগ্রহ করে নিচের লিঙ্কে ক্লিক করুন:","passwordInfo":"উপরের লিঙ্কে প্রবেশ করে নতুন পাসওয়ার্ড তৈরি না করা পর্যন্ত আপনার পাসওয়ার্ড পরিবর্তন হবে না।","resetRequest":"%{appUrl} এর জন্য আপনার ব্লুম হাউজিং পোর্টাল ওয়েবসাইটের পাসওয়ার্ড রিসেট করার একটি অনুরোধ সম্প্রতি করা হয়েছে।","ignoreRequest":"আপনি যদি এটির জন্য অনুরোধ না করে থাকেন, তবে অনুগ্রহ করে এই ইমেলটি উপেক্ষা করুন।","changePassword":"আমার পাসওয়ার্ড পরিবর্তন করুন"},"requestApproval":{"header":"তালিকাভুক্তির অনুমোদনের জন্য অনুরোধ করা হয়েছে","partnerRequest":"একজন অংশীদার %{listingName} লিস্টিংটি প্রকাশ করার জন্য একটি অনুমোদনের অনুরোধ জমা দিয়েছেন।","logInToReviewStart":"অনুগ্রহ করে লগ ইন করুন","logInToReviewEnd":"এবং পর্যালোচনা ও প্রকাশ করার জন্য লিস্টিং ডিটেইল পেজে যান।","accessListing":"লগ ইন করার পর তালিকাটি দেখতে, অনুগ্রহ করে নিচের লিঙ্কে ক্লিক করুন।"},"changesRequested":{"header":"তালিকাভুক্তিতে পরিবর্তনের অনুরোধ করা হয়েছে","adminRequestStart":"একজন প্রশাসক %{listingName} লিস্টিং-এ পরিবর্তনের অনুরোধ করছেন। অনুগ্রহ করে লগ ইন করুন।","adminRequestEnd":"এবং অনুরোধটি দেখতে ও লিস্টিংটি সম্পাদনা করতে লিস্টিং বিস্তারিত পেজে যান।"},"listingApproved":{"header":"নতুন প্রকাশিত তালিকা","adminApproved":"%{listingName} লিস্টিংটি একজন প্রশাসক কর্তৃক অনুমোদিত ও প্রকাশিত হয়েছে।","viewPublished":"প্রকাশিত তালিকাটি দেখতে, অনুগ্রহ করে নিচের লিঙ্কে ক্লিক করুন।"},"csvExport":{"body":"সংযুক্ত ফাইলটি হলো %{fileDescription}। আপনার কোনো প্রশ্ন থাকলে, অনুগ্রহ করে আপনার প্রশাসকের সাথে যোগাযোগ করুন।","hello":"হ্যালো,","title":"%{title}"},"singleUseCodeEmail":{"greeting":"হাই","message":"আপনার %{jurisdictionName} অ্যাকাউন্টে সাইন ইন করতে নিম্নলিখিত কোডটি ব্যবহার করুন। এই কোডটি ১০ মিনিটের জন্য বৈধ থাকবে। এই কোডটি কখনও শেয়ার করবেন না।","singleUseCode":"%{singleUseCode}"},"scriptRunner":{"information":"আপনি পূর্বে ফ্রেমন্ট ফ্যামিলি অ্যাপার্টমেন্টস-এর জন্য আবেদন করেছিলেন, কিন্তু একটি ত্রুটির কারণে আপনার কনফার্মেশন নম্বর ছাড়াই কনফার্মেশন ইমেলটি পাঠানো হয়েছিল। আপনার আবেদন নম্বর এবং কনফার্মেশন নম্বর নিচে পুনরায় পাঠানো হয়েছে। আপনার ধৈর্যের জন্য ধন্যবাদ।","pleaseSave":"অনুগ্রহ করে আপনার রেকর্ডের জন্য এই ইমেলটি সংরক্ষণ করুন।","subject":"ফ্রেমন্ট ফ্যামিলি অ্যাপার্টমেন্টের জন্য আপনার আবেদন নিশ্চিতকরণ নম্বর","yourApplicationNumber":"আপনার আবেদন নম্বর হলো: %{id}","yourConfirmationNumber":"আপনার নিশ্চিতকরণ নম্বরটি হলো: %{confirmationCode}"},"lotteryReleased":{"header":"%{listingName} এর লটারির ফলাফল প্রকাশের জন্য প্রস্তুত।","adminApprovedStart":"%{listingName} এর লটারির ফলাফল প্রকাশের জন্য ছাড়া হয়েছে। অনুগ্রহ করে আপনার লিস্টিং ভিউতে যান।","adminApprovedEnd":"লটারি ট্যাব দেখতে এবং লটারির ফলাফল প্রকাশ করতে।"},"lotteryPublished":{"header":"%{listingName} এর লটারির ফলাফল প্রকাশিত হয়েছে।","resultsPublished":"%{listingName} এর লটারির ফলাফল আবেদনকারীদের অ্যাকাউন্টে প্রকাশ করা হয়েছে।"},"lotteryAvailable":{"header":"নতুন আবাসন লটারির ফলাফল উপলব্ধ","resultsAvailable":"%{listingName}-এর আবাসন লটারির ফলাফল পাওয়া গেছে। আরও তথ্যের জন্য আপনার হাউজিং পোর্টাল অ্যাকাউন্ট দেখুন।","signIn":"আপনার ফলাফল দেখতে সাইন ইন করুন।","whatHappensHeader":"এরপর কী হবে?","whatHappensContent":"প্রপার্টি ম্যানেজার প্রতিটি লটারি পছন্দের মধ্যে, লটারির র‍্যাঙ্ক অনুযায়ী আবেদনকারীদের সাথে যোগাযোগ করা শুরু করবেন। যখন সমস্ত ইউনিট পূরণ হয়ে যাবে, তখন প্রপার্টি ম্যানেজার আবেদনকারীদের সাথে যোগাযোগ করা বন্ধ করে দেবেন। প্রপার্টি ম্যানেজার আপনার র‍্যাঙ্কে পৌঁছানোর আগেই সমস্ত ইউনিট পূরণ হয়ে যেতে পারে। যদি এমন হয়, তবে আপনার সাথে যোগাযোগ করা হবে না।","otherOpportunities1":"অন্যান্য আবাসন সুযোগ দেখতে, অনুগ্রহ করে %{appUrl} এ যান। নতুন আবেদনের সুযোগের বিজ্ঞপ্তি পেতে আপনি সাইন আপ করতে পারেন।","otherOpportunities2":"এখানে","otherOpportunities3":"লটারি কীভাবে কাজ করে সে সম্পর্কে জানতে চাইলে, অনুগ্রহ করে লটারি বিভাগটি দেখুন।","otherOpportunities4":"আবাসন পোর্টাল সহায়তা কেন্দ্র"},"accountRemoval":{"subject":"নিষ্ক্রিয়তার কারণে ব্লুম হাউজিং কর্তৃক নির্ধারিত অ্যাকাউন্ট অপসারণ করা হয়েছে।","courtesyText":"আপনাকে জানানোর জন্য এই সৌজন্যমূলক ইমেলটি পাঠানো হচ্ছে যে, আপনার ব্লুম হাউজিং পোর্টাল অ্যাকাউন্টটি ৩ বছর ধরে নিষ্ক্রিয় থাকায়, আমাদের ব্যবহারের শর্তাবলী এবং গোপনীয়তা নীতি অনুসারে আগামী ৩০ দিনের মধ্যে আপনার অ্যাকাউন্টটি মুছে ফেলা হবে। আপনি যদি আপনার অ্যাকাউন্টটি চালু রাখতে চান, তবে অনুগ্রহ করে আগামী মাসের মধ্যে যেকোনো সময় লগ ইন করুন এবং আমরা আপনার অ্যাকাউন্টটিকে পুনরায় সক্রিয় বলে গণ্য করব।","signIn":"ব্লুম হাউজিং-এ সাইন ইন করুন"},"advocateApproved":{"subject":"আপনার অ্যাকাউন্ট অনুমোদিত হয়েছে।","hello":"হ্যালো","approvalMessage":"%{appUrl} এ আপনার অ্যাকাউন্টটি অনুমোদিত হয়েছে।","approvalInfo":"এখন থেকে সাইটে প্রদর্শিত তালিকাগুলোর জন্য <strong>আবাসন আবেদনকারীদের পক্ষ থেকে</strong> অনলাইন আবেদন শুরু করা, সংরক্ষণ করা এবং জমা দেওয়া আপনার জন্য আরও সহজ হবে।","completeMessage":"আপনার অ্যাকাউন্ট তৈরি সম্পন্ন করতে, অনুগ্রহ করে নিচের লিঙ্কে ক্লিক করুন:","createAccount":"আমার অ্যাকাউন্ট তৈরি করুন"},"advocateRejected":{"subject":"আপনার অ্যাকাউন্ট অনুরোধ সম্পর্কে আপডেট","hello":"হ্যালো","rejectionMessageStart":"%{appUrl}-এ একটি অ্যাকাউন্ট তৈরি করার প্রতি আপনার আগ্রহের জন্য ধন্যবাদ।","rejectionMessageEnd":"এই মুহূর্তে আমরা আপনার অ্যাকাউন্টটি অনুমোদন করতে পারছি না।","rejectionInfoStart":"যদি আপনি মনে করেন এই সিদ্ধান্তটি ভুলবশত নেওয়া হয়েছে অথবা যোগ্যতা সম্পর্কে আপনার কোনো প্রশ্ন থাকে, তাহলে অনুগ্রহ করে আমাদের সাথে যোগাযোগ করুন।","rejectionInfoEnd":"আরও তথ্যের জন্য।"}}'::jsonb,
  NULL,
