ոխությունների ամփոփում.", "statusChange": "Ձեր դիմումի կարգավիճակը փոխվել է %{from}-ից մինչև %{to}", "accessibleWaitListChange": "Ձեր հասանելի սպասման ցուցակի համարը %{value} է", "conventionalWaitListChange": "Ձեր սովորական սպասման ցուցակի համարը %{value} է", "statusLabel": "Դիմումի կարգավիճակը", "contactNotice": "Այս պահին որևէ հետագա գործողություն անհրաժեշտ չէ: Եթե ունեք հարցեր այս թարմացման վերաբերյալ, խնդրում ենք կապվել հետևյալ հասցեով՝", "applicantContactNotice": "Եթե ունեք հարցեր այս թարմացման վերաբերյալ, խնդրում ենք կապվել հետևյալ հասցեով.", "viewPrompt": "Ձեր դիմումը դիտելու համար, խնդրում ենք սեղմել ստորև նշված հղումը՝", "viewLink": "Դիտել իմ դիմումը", "advocateViewPrompt": "Ձեր հաճախորդի դիմումը դիտելու համար, խնդրում ենք սեղմել ստորև նշված հղումը.", "advocateViewLink": "Դիտել դիմումը", "applicationStatus": {"submitted": "Ուղարկված է", "declined": "Մերժված է", "receivedUnit": "Ստացել է միավոր", "waitlist": "Սպասման ցուցակ", "waitlistDeclined": "Սպասման ցուցակ - Մերժված է"}}, "confirmation": {"subject": "Ձեր դիմումի հաստատումը", "eligible": {"fcfs": "Համապատասխան դիմորդների հետ կապ կհաստատվի՝ առաջնահերթության կարգով, մինչև թափուր տեղերի լրացումը։", "lottery": "Դիմումների ընդունման ժամկետի ավարտից հետո, որակավորված դիմորդները կդասակարգվեն վիճակախաղի դասակարգման համաձայն։", "waitlist": "Որակավորված դիմորդները կտեղադրվեն սպասման ցուցակում՝ ըստ հերթականության, մինչև սպասման ցուցակի տեղերի լրացումը։", "waitlistLottery": "Որակավորված դիմորդները կտեղադրվեն սպասման ցուցակում՝ վիճակախաղի դասակարգման հերթականության հիման վրա։", "fcfsPreference": "Բնակարանային նախընտրությունները, եթե կիրառելի են, կազդեն «առաջինը գա, առաջինը կսպասարկվի» կարգի վրա:", "waitlistContact": "Սպասման ցուցակում գտնվելու ընթացքում ձեզ հետ կարող են կապ հաստատել՝ հաստատելու համար, որ ցանկանում եք մնալ սպասման ցուցակում։", "waitlistContactAdvocate": "Ձեր հաճախորդի հետ կարող են կապ հաստատել սպասման ցուցակում գտնվելու ընթացքում՝ հաստատելու համար, որ նա ցանկանում է մնալ սպասման ցուցակում։", "lotteryPreference": "Բնակարանային նախընտրությունները, եթե կիրառելի են, կազդեն վիճակախաղի դասակարգման վրա։", "waitlistPreference": "Բնակարանային նախընտրությունները, եթե կիրառելի են, կազդեն սպասման ցուցակի հերթականության վրա։"}, "interview": "Եթե ձեզ հետ կապվեն հարցազրույցի համար, ձեզ կխնդրեն լրացնել ավելի մանրամասն դիմում և տրամադրել հիմնավորող փաստաթղթեր։", "interviewAdvocate": "Եթե ձեր հաճախորդի հետ կապ հաստատեն հարցազրույցի համար, նրան կխնդրեն լրացնել ավելի մանրամասն դիմում և տրամադրել հիմնավորող փաստաթղթեր։", "whatToExpect": {"FCFS": "Դիմորդների հետ կապ կհաստատի անշարժ գույքի գործակալը՝ ըստ հերթականության, մինչև թափուր տեղերի լրացումը։", "lottery": "Դիմորդների հետ գործակալը կապ կհաստատի վիճակախաղի դասակարգման հերթականությամբ՝ մինչև թափուր տեղերի լրացումը։", "noLottery": "Դիմորդների հետ գործակալը կապ կհաստատի սպասման ցուցակում գրանցվելու հերթականությամբ՝ մինչև թափուր տեղերի լրացումը։"}, "whileYouWait": "Մինչ դուք սպասում եք, կան բաներ, որոնք կարող եք անել՝ պատրաստվելու հնարավոր հաջորդ քայլերին և ապագա հնարավորություններին։", "shouldBeChosen": "Եթե ձեր դիմումը ընտրվի, պատրաստ եղեք լրացնել ավելի մանրամասն դիմում և տրամադրել անհրաժեշտ հիմնավորող փաստաթղթերը։", "whatHappensNext": "Ի՞նչ է լինելու հաջորդը։", "questions": "Հարցեր՞", "whatToExpectNext": "Ինչ սպասել հաջորդիվ.", "needToMakeUpdates": "Անհրաժեշտ է թարմացումներ կատարել։", "applicationsClosed": "Դիմում<br /> փակ", "applicationsRanked": "Դիմում<br /> դասակարգված", "eligibleApplicants": {"FCFS": "Համապատասխան դիմորդները կդասակարգվեն ըստ հերթականության՝ <strong>առաջինը եկածը, առաջինը սպասարկվողը</strong> սկզբունքով։", "lottery": "Որակավորված դիմորդները կդասակարգվեն <strong>ըստ նախընտրության և վիճակախաղի դասակարգման</strong> ։", "lotteryDate": "Վիճակախաղը կանցկացվի %{lotteryDate}-ին։"}, "applicationReceived": "Դիմում<br /> ստացած", "prepareForNextSteps": "Պատրաստվեք հաջորդ քայլերին", "thankYouForApplying": "Շնորհակալություն դիմելու համար։ Մենք ստացել ենք Ձեր դիմումը", "readHowYouCanPrepare": "Կարդացեք, թե ինչպես կարող եք պատրաստվել հաջորդ քայլերին", "yourConfirmationNumber": "Ձեր հաստատման համարը", "applicationPeriodCloses": "Դիմումների ընդունման ժամկետի ավարտից հետո գույքի կառավարիչը կսկսի դիմումների մշակումը։", "contactedForAnInterview": "Եթե ձեզ հետ կապվեն հարցազրույցի համար, ապա դուք պետք է լրացնեք ավելի մանրամասն դիմում և տրամադրեք հիմնավորող փաստաթղթեր։", "gotYourConfirmationNumber": "Մենք ստացանք ձեր դիմումը", "gotYourConfirmationNumberOnYourBehalf": "Մենք Ձեր անունից դիմում ենք ստացել"}, "leasingAgent": {"officeHours": "Գրասենյակի ժամեր՝", "propertyManager": "Գույքի կառավարիչ", "contactAgentToUpdateInfo": "Եթե անհրաժեշտ է թարմացնել ձեր դիմումի տեղեկությունները, կրկին մի՛ դիմեք։ Դրա փոխարեն կապվեք այս ցուցակի գործակալի հետ։", "contactAgentForQuestions": "Եթե ունեք հարցեր այս դիմումի վերաբերյալ, խնդրում ենք կապվել այս ցուցակի գործակալի հետ։"}, "mfaCodeEmail": {"message": "Ձեր հաշվի մուտքի կոդը խնդրվել է։", "mfaCode": "Ձեր մուտքի կոդն է՝ %{singleUseCode}"}, "forgotPassword": {"subject": "Մոռացե՞լ եք գաղտնաբառը։", "callToAction": "Եթե դուք իսկապես կատարել եք այս խնդրանքը, խնդրում ենք սեղմել ստորև նշված հղման վրա՝ ձեր գաղտնաբառը վերականգնելու համար։", "passwordInfo": "Ձեր գաղտնաբառը չի փոխվի, մինչև չմտնեք վերևում նշված հղմանը և չստեղծեք նորը։", "resetRequest": "Վերջերս հարցում է արվել ձեր Bloom Housing Portal կայքի %{appUrl} գաղտնաբառը վերականգնելու համար։", "ignoreRequest": "Եթե դուք սա չեք խնդրել, խնդրում ենք անտեսել այս էլ. նամակը։", "changePassword": "Փոխել իմ գաղտնաբառը"}, "requestApproval": {"header": "Հայտը հաստատվել է", "partnerRequest": "Գործընկերը ներկայացրել է %{listingName} ցուցակը հրապարակելու հաստատման հայտ։", "logInToReviewStart": "Խնդրում ենք մուտք գործել", "logInToReviewEnd": "և անցեք ցուցակի մանրամասների էջ՝ վերանայելու և հրապարակելու համար։", "accessListing": "Մուտք գործելուց հետո ցուցակին մուտք գործելու համար սեղմեք ստորև նշված հղմանը"}, "changesRequested": {"header": "Հայտարարության փոփոխությունները խնդրվել են", "adminRequestStart": "Ադմինիստրատորը խնդրում է փոփոխություններ կատարել %{listingName} ցուցակում։ Խնդրում ենք մուտք գործել", "adminRequestEnd": "և անցեք ցուցակի մանրամասների էջ՝ հարցումը դիտելու և ցուցակը խմբագրելու համար։"}, "listingApproved": {"header": "Նոր հրապարակված ցուցակ", "adminApproved": "%{listingName} ցուցակը հաստատվել և հրապարակվել է ադմինիստրատորի կողմից։", "viewPublished": "Հրապարակված ցուցակը դիտելու համար, խնդրում ենք սեղմել ստորև նշված հղումը"}, "csvExport": {"body": "Կից ֆայլը %{fileDescription} է։ Հարցերի դեպքում, խնդրում ենք դիմել ձեր ադմինիստրատորին։", "hello": "Բարև,", "title": "%{title}"}, "singleUseCodeEmail": {"greeting": "Բարև", "message": "Օգտագործեք հետևյալ կոդը՝ ձեր %{jurisdictionName} հաշիվ մուտք գործելու համար: Այս կոդը վավեր կլինի 10 րոպե: Երբեք մի կիսվեք այս կոդով:", "singleUseCode": "%{singleUseCode}"}, "scriptRunner": {"information": "Դուք նախկինում դիմել էիք Ֆրեմոնտի ընտանեկան բնակարաններին, սակայն սխալի պատճառով ձեր հաստատման էլ. նամակն ուղարկվեց առանց ձեր հաստատման համարի։ Ձեր դիմումի համարը և հաստատման համարը վերստին ուղարկվել են ստորև։ Շնորհակալություն ձեր համբերության համար։", "pleaseSave": "Խնդրում ենք պահպանել այս էլ. նամակը ձեր գրառումների համար։", "subject": "Ձեր դիմումի հաստատման համարը Ֆրեմոնտի ընտանեկան բնակարանների համար", "yourApplicationNumber": "Ձեր դիմումի համարն է՝ %{id}", "yourConfirmationNumber": "Ձեր հաստատման համարն է՝ %{confirmationCode}"}, "lotteryReleased": {"header": "%{listingName} վիճակախաղի արդյունքները պատրաստ են հրապարակման", "adminApprovedStart": "%{listingName} վիճակախաղի արդյունքները հրապարակվել են։ Խնդրում ենք անցնել ցուցակի տեսքին ձեր", "adminApprovedEnd": "վիճակախաղի ներդիրը դիտելու և վիճակախաղի արդյունքները հրապարակելու համար։"}, "lotteryPublished": {"header": "Վիճակախաղի արդյունքները հրապարակվել են %{listingName}-ի համար", "resultsPublished": "%{listingName} վիճակախաղի արդյունքները հրապարակվել են դիմորդների հաշիվներում։"}, "lotteryAvailable": {"header": "Բնակարանային վիճակախաղի նոր արդյունքները հայտնի են", "resultsAvailable": "%{listingNam