eAccount": "Ստեղծել իմ հաշիվը"}, "advocateRejected": {"subject": "Հաշվի հարցման վերաբերյալ թարմացում", "hello": "Բարև", "rejectionMessageStart": "Շնորհակալություն %{appUrl}-ում հաշիվ ստեղծելու հետաքրքրության համար։", "rejectionMessageEnd": "Այս պահին մենք չենք կարող հաստատել ձեր հաշիվը։", "rejectionInfoStart": "Եթե կարծում եք, որ այս որոշումը սխալմամբ է կայացվել կամ հարցեր ունեք իրավասության վերաբերյալ, խնդրում ենք կապվել մեզ հետ հետևյալ հասցեով՝", "rejectionInfoEnd": "ավելի շատ տեղեկությունների համար։"}}'::jsonb
