 են, կազդեն վիճակախաղի դասակարգման վրա։", "waitlistPreference": "Բնակարանային նախընտրությունները, եթե կիրառելի են, կազդեն սպասման ցուցակի հերթականության վրա։"}, "interview": "Եթե ձեզ հետ կապվեն հարցազրույցի համար, ձեզ կխնդրեն լրացնել ավելի մանրամասն դիմում և տրամադրել հիմնավորող փաստաթղթեր։", "interviewAdvocate": "Եթե ձեր հաճախորդի հետ կապ հաստատեն հարցազրույցի համար, նրան կխնդրեն լրացնել ավելի մանրամասն դիմում և տրամադրել հիմնավորող փաստաթղթեր։", "whatToExpect": {"FCFS": "Դիմորդների հետ կապ կհաստատի անշարժ գույքի գործակալը՝ ըստ հերթականության, մինչև թափուր տեղերի լրացումը։", "lottery": "Դիմորդների հետ գործակալը կապ կհաստատի վիճակախաղի դասակարգման հերթականությամբ՝ մինչև թափուր տեղերի լրացումը։", "noLottery": "Դիմորդների հետ գործակալը կապ կհաստատի սպասման ցուցակում գրանցվելու հերթականությամբ՝ մինչև թափուր տեղերի լրացումը։"}, "whileYouWait": "Մինչ դուք սպասում եք, կան բաներ, որոնք կարող եք անել՝ պատրաստվելու հնարավոր հաջորդ քայլերին և ապագա հնարավորություններին։", "shouldBeChosen": "Եթե ձեր դիմումը ընտրվի, պատրաստ եղեք լրացնել ավելի մանրամասն դիմում և տրամադրել անհրաժեշտ հիմնավորող փաստաթղթերը։", "whatHappensNext": "Ի՞նչ է լինելու հաջորդը։", "questions": "Հարցեր՞", "whatToExpectNext": "Ինչ սպասել հաջորդիվ.", "needToMakeUpdates": "Անհրաժեշտ է թարմացումներ կատարել։", "applicationsClosed": "Դիմում<br /> փակ", "applicationsRanked": "Դիմում<br /> դասակարգված", "eligibleApplicants": {"FCFS": "Համապատասխան դիմորդները կդասակարգվեն ըստ հերթականության՝ <strong>առաջինը եկածը, առաջինը սպասարկվողը</strong> սկզբունքով։", "lottery": "Որակավորված դիմորդները կդասակարգվեն <strong>ըստ նախընտրության և վիճակախաղի դասակարգման</strong> ։", "lotteryDate": "Վիճակախաղը կանցկացվի %{lotteryDate}-ին։"}, "applicationReceived": "Դիմում<br /> ստացած", "prepareForNextSteps": "Պատրաստվեք հաջորդ քայլերին", "thankYouForApplying": "Շնորհակալություն դիմելու համար։ Մենք ստացել ենք Ձեր դիմումը", "readHowYouCanPrepare": "Կարդացեք, թե ինչպես կարող եք պատրաստվել հաջորդ քայլերին", "yourConfirmationNumber": "Ձեր հաստատման համարը", "applicationPeriodCloses": "Դիմումների ընդունման ժամկետի ավարտից հետո գույքի կառավարիչը կսկսի դիմումների մշակումը։", "contactedForAnInterview": "Եթե ձեզ հետ կապվեն հարցազրույցի համար, ապա դուք պետք է լրացնեք ավելի մանրամասն դիմում և տրամադրեք հիմնավորող փաստաթղթեր։", "gotYourConfirmationNumber": "Մենք ստացանք ձեր դիմումը", "gotYourConfirmationNumberOnYourBehalf": "Մենք Ձեր անունից դիմում ենք ստացել"}, "leasingAgent": {"officeHours": "Գրասենյակի ժամեր՝", "propertyManager": "Գույքի կառավարիչ", "contactAgentToUpdateInfo": "Եթե անհրաժեշտ է թարմացնել ձեր դիմումի տեղեկությունները, կրկին մի՛ դիմեք։ Դրա փոխարեն կապվեք այս ցուցակի գործակալի հետ։", "contactAgentForQuestions": "Եթե ունեք հարցեր այս դիմումի վերաբերյալ, խնդրում ենք կապվել այս ցուցակի գործակալի հետ։"}, "mfaCodeEmail": {"message": "Ձեր հաշվի մուտքի կոդը խնդրվել է։", "mfaCode": "Ձեր մուտքի կոդն է՝ %{singleUseCode}"}, "forgotPassword": {"subject": "Մոռացե՞լ եք գաղտնաբառը։", "callToAction": "Եթե դուք իսկապես կատարել եք այս խնդրանքը, խնդրում ենք սեղմել ստորև նշված հղման վրա՝ ձեր գաղտնաբառը վերականգնելու համար։", "passwordInfo": "Ձեր գաղտնաբառը չի փոխվի, մինչև չմտնեք վերևում նշված հղմանը և չստեղծեք նորը։", "resetRequest": "Վերջերս հարցում է արվել ձեր Bloom Housing Portal կայքի %{appUrl} գաղտնաբառը վերականգնելու համար։", "ignoreRequest": "Եթե դուք սա չեք խնդրել, խնդրում ենք անտեսել այս էլ. նամակը։", "changePassword": "Փոխել իմ գաղտնաբառը"}, "requestApproval": {"header": "Հայտը հաստատվել է", "partnerRequest": "Գործընկերը ներկայացրել է %{listingName} ցուցակը հրապարակելու հաստատման հայտ։", "logInToReviewStart": "Խնդրում ենք մուտք գործել", "logInToReviewEnd": "և անցեք ցուցակի մանրամասների էջ՝ վերանայելու և հրապարակելու համար։", "accessListing": "Մուտք գործելուց հետո ցուցակին մուտք գործելու համար սեղմեք ստորև նշված հղմանը"}, "changesRequested": {"header": "Հայտարարության փոփոխությունները խնդրվել են", "adminRequestStart": "Ադմինիստրատորը խնդրում է փոփոխություններ կատարել %{listingName} ցուցակում։ Խնդրում ենք մուտք գործել", "adminRequestEnd": "և անցեք ցուցակի մանրամասների էջ՝ հարցումը դիտելու և ցուցակը խմբագրելու համար։"}, "listingApproved": {"header": "Նոր հրապարակված ցուցակ", "adminApproved": "%{listingName} ցուցակը հաստատվել և հրապարակվել է ադմինիստրատորի կողմից։", "viewPublished": "Հրապարակված ցուցակը դիտելու համար, խնդրում ենք սեղմել ստորև նշված հղումը"}, "csvExport": {"body": "Կից ֆայլը %{fileDescription} է։ Հարցերի դեպքում, խնդրում ենք դիմել ձեր ադմինիստրատորին։", "hello": "Բարև,", "title": "%{title}"}, "singleUseCodeEmail": {"greeting": "Բարև", "message": "Օգտագործեք հետևյալ կոդը՝ ձեր %{jurisdictionName} հաշիվ մուտք գործելու համար: Այս կոդը վավեր կլինի 10 րոպե: Երբեք մի կիսվեք այս կոդով:", "singleUseCode": "%{singleUseCode}"}, "scriptRunner": {"information": "Դուք նախկինում դիմել էիք Ֆրեմոնտի ընտանեկան բնակարաններին, սակայն սխալի պատճառով ձեր հաստատման էլ. նամակն ուղարկվեց առանց ձեր հաստատման համարի։ Ձեր դիմումի համարը և հաստատման համարը վերստին ուղարկվել են ստորև։ Շնորհակալություն ձեր համբերության համար։", "pleaseSave": "Խնդրում ենք պահպանել այս էլ. նամակը ձեր գրառումների համար։", "subject": "Ձեր դիմումի հաստատման համարը Ֆրեմոնտի ընտանեկան բնակարանների համար", "yourApplicationNumber": "Ձեր դիմումի համարն է՝ %{id}", "yourConfirmationNumber": "Ձեր հաստատման համարն է՝ %{confirmationCode}"}, "lotteryReleased": {"header": "%{listingName} վիճակախաղի արդյունքները պատրաստ են հրապարակման", "adminApprovedStart": "%{listingName} վիճակախաղի արդյունքները հրապարակվել են։ Խնդրում ենք անցնել ցուցակի տեսքին ձեր", "adminApprovedEnd": "վիճակախաղի ներդիրը դիտելու և վիճակախաղի արդյունքները հրապարակելու համար։"}, "lotteryPublished": {"header": "Վիճակախաղի արդյունքները հրապարակվել են %{listingName}-ի համար", "resultsPublished": "%{listingName} վիճակախաղի արդյունքները հրապարակվել են դիմորդների հաշիվներում։"}, "lotteryAvailable": {"header": "Բնակարանային վիճակախաղի նոր արդյունքները հայտնի են", "resultsAvailable": "%{listingName}-ի բնակարանային վիճակախաղի արդյունքները հասանելի են։ Լրացուցիչ տեղեկությունների համար այցելեք ձեր բնակարանային պորտալի հաշիվը։", "signIn": "Մուտք գործեք՝ ձեր արդյունքները տեսնելու համար", "whatHappensHeader": "Ի՞նչ է լինելու հաջորդը։", "whatHappensContent": "Գույքի կառավարիչը կսկսի կապ հաստատել դիմորդների հետ՝ վիճակախաղի դասակարգման հերթականությամբ, յուրաքանչյուր վիճակախաղի նախընտրության շրջանակներում: Երբ բնակարանները բոլորը լցվեն, գույքի կառավարիչը կդադարի կապ հաստատել դիմորդների հետ: Բոլոր բնակարանները կարող են լցվել նախքան գույքի կառավարիչը հասնի ձեր դասակարգմանը: Եթե դա տեղի ունենա, ձեզ հետ կապ չեն հաստատի:", "otherOpportunities1": "Այլ բնակարանային հնարավորություններ դիտելու համար այցելեք %{appUrl} կայքը։ Կարող եք գրանցվել՝ նոր դիմումների հնարավորությունների մասին ծանուցումներ ստանալու համար։", "otherOpportunities2": "այստեղ", "otherOpportunities3": "Եթե ցանկանում եք իմանալ, թե ինչպես են գործում վիճակախաղերը, խնդրում ենք դիտել վիճակախաղի բաժինը։", "otherOpportunities4": "Բնակարանային պորտալի օգնության կենտրոն"}, "accountRemoval": {"subject": "Bloom Housing-ը պլանավորել է հաշվի հեռացում անգործունեության պատճառով", "courtesyText": "Սա քաղաքավարության նամակ է, որը Ձեզ տեղեկացնում է, որ քանի որ Ձեր Bloom Housing Portal հաշիվը 3 տարի անգործուն է եղել, այն կջնջվի 30 օրվա ընթացքում՝ համաձայն մեր օգտագործման պայմանների և գաղտնիության քաղաքականության: Եթե ցանկանում եք պահպանել Ձեր հաշիվը, խնդրում ենք մուտք գործել հաջորդ ամսվա ընթացքում, և մենք Ձեր հաշիվը կրկին կհամարենք ակտիվ:", "signIn": "Մուտք գործեք Bloom Housing-ում"}, "advocateApproved": {"subject": "Ձեր հաշիվը հաստատվել է", "hello": "Բարև", "approvalMessage": "Ձեր հաշիվը %{appUrl}-ում հաստատվել է։", "approvalInfo": "Այժմ ձեզ համար ավելի հեշտ կլինի սկսել, պահպանել և ներկայացնել առցանց դիմումներ կայքում հայտնված <strong>բնակարանային դիմորդների անունից</strong> ՝ կայքում հայտնված հայտարարությունների համար։", "completeMessage": "Ձեր հաշվի ստեղծումն ավարտելու համար, խնդրում ենք սեղմել ստորև նշված հղման վրա՝", "createAccount": "Ստեղծել իմ հաշիվը"}, "advocateRejected": {"sub